/* ============ SUPABASE DATA HOOK ============ */
function useTable(table:string, userId:string|null) {
  const [data, setData] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);

  const load = useCallback(async () => {
    if (!userId) return;
    const { data: rows } = await supabase.from(table).select("*").eq("user_id", userId).order("created_at", { ascending: false });
    setData(rows || []);
    setLoading(false);
  }, [table, userId]);

  useEffect(() => { load(); }, [load]);
  useEffect(()=>{const h=(e:any)=>{const t=e?.detail?.table;if(!t||t===table)load();};window.addEventListener("ks-refresh",h);return ()=>window.removeEventListener("ks-refresh",h);},[table,load]);

  const add = async (row: any) => {
    const { data: inserted, error } = await supabase.from(table).insert({ ...row, user_id: userId }).select().single();
    if (error) console.error(`Ошибка вставки в «${table}»:`, error.message, error);
    if (inserted) setData(prev => [inserted, ...prev]);
    return inserted;
  };

  const update = async (id: string, updates: any) => {
    const { error } = await supabase.from(table).update(updates).eq("id", id);
    if (error) console.error(`Ошибка обновления «${table}»:`, error.message, error);
    setData(prev => prev.map(r => r.id === id ? { ...r, ...updates } : r));
  };

  const remove = async (id: string) => {
    await supabase.from(table).delete().eq("id", id);
    setData(prev => prev.filter(r => r.id !== id));
  };

  return { data, loading, add, update, remove, reload: load, setData };
}

/* ============ AUTH ============ */
function Auth({ onLogin }: { onLogin: (u: any) => void }) {
  const [email, setEmail] = useState("");
  const [pw, setPw] = useState("");
  const [err, setErr] = useState("");
  const [loading, setLoading] = useState(false);

  const login = async () => {
    setErr(""); setLoading(true);
    const { data, error } = await supabase.auth.signInWithPassword({ email, password: pw });
    setLoading(false);
    if (error) return setErr("Неверный email или пароль");
    if (data.user) onLogin(data.user);
  };

  return (
    <div style={{minHeight:"100vh",background:`linear-gradient(135deg,${C.dk},${C.da},${C.a})`,display:"flex",alignItems:"center",justifyContent:"center",fontFamily:"'Inter',sans-serif",padding:20}}>
      <div style={{background:C.w,borderRadius:12,padding:"48px 40px",width:"100%",maxWidth:420,boxShadow:"0 24px 80px rgba(0,0,0,0.25)"}}>
        <div style={{textAlign:"center",marginBottom:36}}>
          <div style={{display:"inline-flex",alignItems:"center",gap:10,background:C.dk,padding:"14px 28px",borderRadius:8}}>
            <Logo s={40}/><Brand size="lg"/>
          </div>
        </div>
        <div style={{fontSize:16,fontWeight:600,textAlign:"center",marginBottom:24,color:C.t1}}>Вход в платформу</div>
        <div style={{display:"flex",flexDirection:"column",gap:14}}>
          <input placeholder="Email" type="email" value={email} onChange={e=>setEmail(e.target.value)} style={iS()}/>
          <input placeholder="Пароль" type="password" value={pw} onChange={e=>setPw(e.target.value)} style={iS()} onKeyDown={e=>e.key==="Enter"&&login()}/>
          {err&&<div style={{background:"#FEF2F2",color:C.r,padding:"10px 14px",borderRadius:8,fontSize:13,fontWeight:500}}>{err}</div>}
          <Btn onClick={login} style={{width:"100%",padding:"14px 0",fontSize:15,marginTop:8,opacity:loading?0.6:1}}>
            {loading?"Вход...":"Войти"}
          </Btn>
        </div>
      </div>
    </div>
  );
}

/* ============ MOBILE HOOK ============ */
function useIsMobile(){
  const[m,setM]=useState(()=>typeof window!=="undefined"&&window.innerWidth<768);
  useEffect(()=>{
    const h=()=>setM(window.innerWidth<768);
    window.addEventListener("resize",h);
    return()=>window.removeEventListener("resize",h);
  },[]);
  return m;
}

/* ============ SIDEBAR — Deep Dark Glass ============ */
function Side({active,onNav,onLogout,collapsed:controlledCollapsed,onCollapsedChange}:{active:string,onNav:(id:string)=>void,onLogout:()=>void,collapsed?:boolean,onCollapsedChange?:(collapsed:boolean)=>void}){
  const{dark,toggle}=useTheme();
  const[localCollapsed,setLocalCollapsed]=useState(false);
  const collapsed=controlledCollapsed ?? localCollapsed;
  const setCollapsed=(next:boolean)=>{
    if(onCollapsedChange)onCollapsedChange(next);
    else setLocalCollapsed(next);
  };
  const activeGroupIdx=NAV_GROUPS.findIndex(g=>g.items.some(i=>i.id===active));
  const[openGroups,setOpenGroups]=useState<number[]>(()=>[activeGroupIdx>=0?activeGroupIdx:0]);

  const toggleGroup=(idx:number)=>{
    setOpenGroups(p=>p.includes(idx)?p.filter(i=>i!==idx):[...p,idx]);
  };

  const AI_ICONS:Record<string,string>={
    ai:"/icon-ai.png",script:"/icon-copy.png",
    product:"/icon-product.png",stories:"/icon-stories.png",
    design:"/icon-design.png",
  };

  const getAccent=(n:any)=>(n.accent==="gradient"?null:n.accent||null);

  const renderItem=(n:any)=>{
    const isActive=active===n.id;
    const accent=getAccent(n)||"#878787";
    const isGrad=n.accent==="gradient";
    const customIcon=AI_ICONS[n.id];
    // Parse accent to rgb for backgrounds
    const r=parseInt(accent.slice(1,3),16)||79;
    const g2=parseInt(accent.slice(3,5),16)||142;
    const b=parseInt(accent.slice(5,7),16)||247;

    return(
      <button key={n.id} onClick={()=>onNav(n.id)} title={collapsed?n.label:undefined}
        style={{
          display:"flex",alignItems:"center",gap:10,
          padding:collapsed?"9px 0":"7px 10px 7px 10px",
          justifyContent:collapsed?"center":"flex-start",
          borderRadius:8,
          cursor:"pointer",width:"100%",
          position:"relative",overflow:"hidden",
          transition:"all 0.25s cubic-bezier(0.4,0,0.2,1)",
          outline:"none",
          marginBottom:1,
          background:isActive
            ?("rgba("+r+","+g2+","+b+",0.13)")
            :"rgba(255,255,255,0.0)",
          backdropFilter:isActive?"blur(12px) saturate(1.6)":"none",
          WebkitBackdropFilter:isActive?"blur(12px) saturate(1.6)":"none",
          boxShadow:isActive
            ?("0 0 20px rgba("+r+","+g2+","+b+",0.2), inset 0 1px 0 rgba(255,255,255,0.08)")
            :"none",
          border:isActive
            ?("1px solid rgba("+r+","+g2+","+b+",0.25)")
            :"1px solid transparent",
        }}
        onMouseEnter={e=>{
          const el=e.currentTarget as HTMLElement;
          if(!isActive){
            el.style.background="rgba("+r+","+g2+","+b+",0.07)";
            el.style.backdropFilter="blur(8px)";
            (el.style as any).WebkitBackdropFilter="blur(8px)";
            el.style.border="1px solid rgba("+r+","+g2+","+b+",0.12)";
            el.style.transform="translateX(2px)";
          }
        }}
        onMouseLeave={e=>{
          const el=e.currentTarget as HTMLElement;
          if(!isActive){
            el.style.background="rgba(255,255,255,0)";
            el.style.backdropFilter="none";
            (el.style as any).WebkitBackdropFilter="none";
            el.style.border="1px solid transparent";
            el.style.transform="translateX(0)";
          }
        }}>

        {/* Active left glow bar — gradient */}
        {isActive&&<div style={{
          position:"absolute",left:0,top:"16%",bottom:"16%",width:3,
          borderRadius:"0 3px 3px 0",
          background:isGrad
            ?"linear-gradient(180deg,#C8C8C8,#A0A0A0)"
            :"linear-gradient(180deg,rgba("+r+","+g2+","+b+",1),rgba("+r+","+g2+","+b+",0.4))",
          boxShadow:"0 0 12px rgba("+r+","+g2+","+b+",0.8), 0 0 24px rgba("+r+","+g2+","+b+",0.4)",
        }}/>}

        {/* Shimmer overlay */}
        {isActive&&<div style={{
          position:"absolute",inset:0,borderRadius:8,
          background:"linear-gradient(105deg,transparent 30%,rgba(255,255,255,0.04) 50%,transparent 70%)",
          backgroundSize:"200% 100%",
          animation:"shimmer 4s ease-in-out infinite",
          pointerEvents:"none",
        }}/>}

        {/* Ambient glow blob on active */}
        {isActive&&<div style={{
          position:"absolute",right:-10,top:"50%",transform:"translateY(-50%)",
          width:50,height:50,borderRadius:"50%",
          background:"radial-gradient(circle,rgba("+r+","+g2+","+b+",0.15) 0%,transparent 70%)",
          pointerEvents:"none",
          filter:"blur(8px)",
        }}/>}

        {/* Icon wrapper — glass pill */}
        <div style={{
          width:26,height:26,borderRadius:8,flexShrink:0,
          display:"flex",alignItems:"center",justifyContent:"center",
          overflow:"hidden",
          background:customIcon?"transparent"
            :isActive
              ?isGrad
                ?"linear-gradient(135deg,rgba(200,200,200,0.3),rgba(160,160,160,0.3))"
                :"rgba("+r+","+g2+","+b+",0.2)"
              :`rgba(255,255,255,0.04)`,
          border:isActive
            ?"1px solid rgba("+r+","+g2+","+b+",0.35)"
            :"1px solid rgba(255,255,255,0.05)",
          boxShadow:isActive
            ?"0 0 10px rgba("+r+","+g2+","+b+",0.3), inset 0 1px 0 rgba(255,255,255,0.12)"
            :"none",
          transition:"all 0.25s",
        }}>
          {customIcon
            ?<img src={customIcon} width={26} height={26} style={{borderRadius:8,objectFit:"cover",opacity:isActive?1:0.5}} alt={n.label}/>
            :<I path={n.ic} size={13}
                color={isActive?(isGrad?"#E3E3E3":accent):"rgba(255,255,255,0.4)"}
                sw={isActive?2:1.5}/>
          }
        </div>

        {!collapsed&&<span style={{
          fontSize:12.5,fontWeight:isActive?600:400,flex:1,textAlign:"left",
          color:isActive
            ?(isGrad?"#E3E3E3":accent==="gradient"?"#C8C8C8":accent)
            :"rgba(255,255,255,0.5)",
          overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap",
          transition:"color 0.2s",
          letterSpacing:isActive?0.1:0,
        }}>{n.label}</span>}

        {/* Active dot */}
        {!collapsed&&isActive&&<div style={{
          width:5,height:5,borderRadius:"50%",flexShrink:0,
          background:isGrad
            ?"linear-gradient(135deg,#C8C8C8,#A0A0A0)"
            :accent,
          boxShadow:"0 0 6px rgba("+r+","+g2+","+b+",0.8), 0 0 12px rgba("+r+","+g2+","+b+",0.5)",
        }}/>}
      </button>
    );
  };

  const SB_BG="linear-gradient(180deg,#0C0C0C 0%,#0A0A0A 100%)";

  return(
    <div style={{
      width:collapsed?64:248,height:"100vh",
      background:SB_BG,
      display:"flex",flexDirection:"column",
      transition:"width 0.3s cubic-bezier(0.4,0,0.2,1)",
      position:"fixed",left:0,top:0,zIndex:100,
      overflowX:"hidden",overflowY:"hidden",
      borderRight:"1px solid rgba(255,255,255,0.05)",
    }}>
      <style>{`
        @keyframes shimmer{
          0%{background-position:-200% center}
          100%{background-position:200% center}
        }
        @keyframes borderGlow{
          0%,100%{border-color:rgba(135,135,135,0.15)}
          50%{border-color:rgba(135,135,135,0.4)}
        }
        .sb-scroll::-webkit-scrollbar{width:2px}
        .sb-scroll::-webkit-scrollbar-thumb{background:rgba(255,255,255,0.05);border-radius:2px}
      `}</style>

      {/* Top ambient glow */}
      <div style={{
        position:"absolute",top:-60,left:"50%",transform:"translateX(-50%)",
        width:200,height:120,
        background:"transparent",
        pointerEvents:"none",
      }}/>

      {/* Logo */}
      <div style={{
        padding:collapsed?"18px 0":"18px 16px",
        display:"flex",alignItems:"center",gap:10,
        justifyContent:collapsed?"center":"flex-start",
        borderBottom:"1px solid rgba(255,255,255,0.05)",
        flexShrink:0,position:"relative",
      }}>
        <div style={{
          width:36,height:36,borderRadius:8,
          background:"linear-gradient(135deg,#1E1E1E,#141414)",
          border:"1px solid rgba(255,255,255,0.1)",
          display:"flex",alignItems:"center",justifyContent:"center",
          boxShadow:"inset 0 1px 0 rgba(255,255,255,0.05)",
          flexShrink:0,
        }}>
          <Logo s={26}/>
        </div>
        {!collapsed&&<div style={{display:"flex",flexDirection:"column",lineHeight:1.2}}>
          <span style={{fontSize:14,fontWeight:800,color:"#ECECEC",letterSpacing:1.5}}>VIZZY</span>
          <span style={{fontSize:8,color:"rgba(255,255,255,0.25)",letterSpacing:1}}>by Kirill Scales</span>
        </div>}
      </div>

      {/* Nav */}
      <div className="sb-scroll" style={{flex:1,overflowY:"auto",overflowX:"hidden",padding:"10px 8px 0"}}>
        {NAV_GROUPS.map((group,gi)=>{
          const isOpen=collapsed||(group as any).alwaysOpen||!group.label||openGroups.includes(gi);
          const hasActiveItem=group.items.some(i=>i.id===active);
          const isAlwaysOpen=(group as any).alwaysOpen;

          return(
            <div key={gi} style={{marginBottom:6}}>
              {group.label&&!collapsed&&(
                isAlwaysOpen
                  // MAIN block — non-clickable label, no chevron
                  ?<div style={{padding:"8px 10px 4px"}}>
                    <span style={{
                      fontSize:9,fontWeight:700,
                      color:hasActiveItem
                        ?((group.items.find(i=>i.id===active)?.accent||"rgba(135,135,135,0.7)")+"bb")
                        :"rgba(255,255,255,0.18)",
                      letterSpacing:1.8,textTransform:"uppercase",
                    }}>{group.label}</span>
                  </div>
                  :<button onClick={()=>toggleGroup(gi)}
                    style={{
                      width:"100%",display:"flex",alignItems:"center",
                      justifyContent:"space-between",
                      padding:"8px 10px 4px",border:"none",
                      background:"transparent",cursor:"pointer",borderRadius:8,
                      transition:"background 0.15s",
                    }}
                    onMouseEnter={e=>{(e.currentTarget as HTMLElement).style.background="rgba(255,255,255,0.03)";}}
                    onMouseLeave={e=>{(e.currentTarget as HTMLElement).style.background="transparent";}}>
                    <span style={{
                      fontSize:9,fontWeight:700,
                      color:hasActiveItem
                        ?((group.items.find(i=>i.id===active)?.accent||"rgba(135,135,135,0.7)")+"bb")
                        :"rgba(255,255,255,0.18)",
                      letterSpacing:1.8,textTransform:"uppercase",
                    }}>{group.label}</span>
                    <svg width="9" height="9" viewBox="0 0 24 24" fill="none"
                      stroke={hasActiveItem?"rgba(255,255,255,0.25)":"rgba(255,255,255,0.15)"}
                      strokeWidth="2.5"
                      style={{transform:isOpen?"rotate(0deg)":"rotate(-90deg)",transition:"transform 0.25s ease"}}>
                      <polyline points="6 9 12 15 18 9"/>
                    </svg>
                  </button>
              )}

              {group.label&&collapsed&&gi>0&&(
                <div style={{height:1,background:"rgba(255,255,255,0.04)",margin:"6px 10px"}}/>
              )}

              <div style={{
                display:"flex",flexDirection:"column",gap:2,
                maxHeight:isOpen?"600px":"0",
                overflow:"hidden",
                transition:"max-height 0.35s cubic-bezier(0.4,0,0.2,1)",
              }}>
                {group.items.map(n=>renderItem(n))}
              </div>
            </div>
          );
        })}
      </div>

      {/* Bottom */}
      <div style={{
        padding:"10px 8px 12px",
        borderTop:"1px solid rgba(255,255,255,0.04)",
        flexShrink:0,display:"flex",flexDirection:"column",gap:4,
      }}>
        {/* Theme toggle */}
        <div style={{
          display:"flex",alignItems:"center",
          justifyContent:collapsed?"center":"space-between",
          padding:collapsed?"10px 0":"8px 10px",
        }}>
          {!collapsed&&<span style={{fontSize:10,color:"rgba(255,255,255,0.25)",letterSpacing:0.5}}>Тема интерфейса</span>}
          <button onClick={toggle}
            style={{
              width:48,height:26,borderRadius:10,flexShrink:0,
              background:dark
                ?"linear-gradient(90deg,#3B3B3B,#5B5B5B)"
                :"rgba(255,255,255,0.1)",
              border:`1px solid ${dark?"rgba(135,135,135,0.4)":"rgba(255,255,255,0.1)"}`,
              cursor:"pointer",position:"relative",
              boxShadow:dark?"0 0 12px rgba(135,135,135,0.25)":"none",
              transition:"all 0.4s ease",
              outline:"none",
            }}>
            <div style={{
              position:"absolute",top:2,
              left:dark?24:2,
              width:20,height:20,borderRadius:"50%",
              background:dark?"#E9E9E9":"rgba(255,255,255,0.7)",
              transition:"left 0.35s cubic-bezier(0.4,0,0.2,1)",
              display:"flex",alignItems:"center",justifyContent:"center",
              fontSize:11,
              boxShadow:dark?"0 0 8px rgba(135,135,135,0.6)":"0 1px 4px rgba(0,0,0,0.2)",
            }}>
              {dark?"🌙":"☀️"}
            </div>
          </button>
        </div>

        {/* Collapse */}
        <button onClick={()=>setCollapsed(!collapsed)}
          style={{
            width:"100%",display:"flex",alignItems:"center",gap:8,
            padding:collapsed?"10px 0":"7px 10px",
            justifyContent:collapsed?"center":"flex-start",
            border:"none",borderRadius:8,cursor:"pointer",
            background:"transparent",color:"rgba(255,255,255,0.25)",
            fontSize:12,transition:"all 0.15s",outline:"none",
          }}
          onMouseEnter={e=>{(e.currentTarget as HTMLElement).style.background="rgba(255,255,255,0.04)";(e.currentTarget as HTMLElement).style.color="rgba(255,255,255,0.55)";}}
          onMouseLeave={e=>{(e.currentTarget as HTMLElement).style.background="transparent";(e.currentTarget as HTMLElement).style.color="rgba(255,255,255,0.25)";}}>
          <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round">
            {collapsed?<polyline points="9 18 15 12 9 6"/>:<polyline points="15 18 9 12 15 6"/>}
          </svg>
          {!collapsed&&<span>Свернуть</span>}
        </button>

        {/* Logout */}
        <button onClick={onLogout}
          style={{
            width:"100%",display:"flex",alignItems:"center",gap:8,
            padding:collapsed?"10px 0":"7px 10px",
            justifyContent:collapsed?"center":"flex-start",
            border:"none",borderRadius:8,cursor:"pointer",
            background:"transparent",color:"rgba(255,255,255,0.2)",
            fontSize:12,transition:"all 0.15s",outline:"none",
          }}
          onMouseEnter={e=>{(e.currentTarget as HTMLElement).style.background="rgba(119,119,119,0.08)";(e.currentTarget as HTMLElement).style.color="#777777";}}
          onMouseLeave={e=>{(e.currentTarget as HTMLElement).style.background="transparent";(e.currentTarget as HTMLElement).style.color="rgba(255,255,255,0.2)";}}>
          <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
            <path d="M9 21H5a2 2 0 01-2-2V5a2 2 0 012-2h4"/>
            <polyline points="16 17 21 12 16 7"/>
            <line x1="21" y1="12" x2="9" y2="12"/>
          </svg>
          {!collapsed&&<span>Выйти</span>}
        </button>
      </div>
    </div>
  );
}

/* ============ MOBILE NAV ============ */
// Shows top 5 most important nav items + "More" drawer
const MOB_MORE_EXCLUDE=["dashboard","strategy","content","ai"];
const MOB_LABELS:Record<string,string>={dashboard:"Дашборд",strategy:"War",content:"Контент"};
function MobileNav({active,onNav,onLogout}:{active:string,onNav:(id:string)=>void,onLogout:()=>void}){
  const[drawerOpen,setDrawerOpen]=useState(false);
  const byId=(id:string)=>NAV.find(n=>n.id===id)!;
  const more=NAV.filter(n=>!MOB_MORE_EXCLUDE.includes(n.id));
  const BLUE_ON="#5B9BFF";
  const aiActive=active==="ai";
  const moreActive=!MOB_MORE_EXCLUDE.includes(active);

  const tabBtn=(id:string)=>{
    const n=byId(id);const a=active===id;
    return <button key={id} onClick={()=>{onNav(id);setDrawerOpen(false);}}
      style={{flex:1,display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",gap:4,border:"none",background:"transparent",cursor:"pointer",padding:"8px 2px",position:"relative"}}>
      {a&&<div style={{position:"absolute",top:0,width:22,height:3,borderRadius:"0 0 3px 3px",background:BLUE_ON}}/>}
      <I path={n.ic} size={22} color={a?"#fff":"rgba(255,255,255,0.5)"} sw={a?2:1.6}/>
      <span style={{fontSize:9.5,color:a?"#fff":"rgba(255,255,255,0.5)",fontWeight:a?700:500,lineHeight:1,letterSpacing:0.2}}>{MOB_LABELS[id]||n.label.split(" ")[0]}</span>
    </button>;
  };

  return <>
    {/* Bottom nav bar */}
    <div style={{position:"fixed",bottom:0,left:0,right:0,background:C.dk,zIndex:200,borderTop:"1px solid rgba(255,255,255,0.08)",display:"flex",alignItems:"stretch",height:62,paddingBottom:"env(safe-area-inset-bottom)",boxShadow:"0 -4px 24px rgba(0,0,0,0.28)"}}>
      {tabBtn("dashboard")}
      {tabBtn("strategy")}

      {/* Center AI FAB */}
      <div style={{flex:1,display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"flex-end",paddingBottom:6,position:"relative"}}>
        <button onClick={()=>{onNav("ai");setDrawerOpen(false);}} aria-label="Kirill Scales AI"
          style={{position:"absolute",top:-24,width:58,height:58,borderRadius:"50%",border:aiActive?"3px solid rgba(91,155,255,0.45)":"3px solid "+C.dk,background:"linear-gradient(160deg,#5B9BFF 0%,#2563EB 55%,#1D4ED8 100%)",cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",boxShadow:"0 6px 18px rgba(37,99,235,0.5),0 2px 6px rgba(0,0,0,0.35)",transition:"transform 0.15s"}}
          onTouchStart={e=>{(e.currentTarget as HTMLElement).style.transform="scale(0.94)";}}
          onTouchEnd={e=>{(e.currentTarget as HTMLElement).style.transform="scale(1)";}}>
          <svg width="28" height="28" viewBox="0 0 24 24" fill="none">
            <path d="M12 2.6l1.75 4.9L18.5 9.2l-4.75 1.7L12 15.8l-1.75-4.9L5.5 9.2l4.75-1.7L12 2.6z" fill="#fff"/>
            <circle cx="18.6" cy="16.6" r="1.7" fill="#fff" opacity="0.92"/>
            <circle cx="6" cy="17.2" r="1.15" fill="#fff" opacity="0.72"/>
          </svg>
        </button>
        <span style={{fontSize:9.5,color:aiActive?"#fff":"rgba(255,255,255,0.55)",fontWeight:aiActive?700:600,lineHeight:1,marginBottom:2}}>Ассистент</span>
      </div>

      {tabBtn("content")}

      {/* More button */}
      <button onClick={()=>setDrawerOpen(!drawerOpen)}
        style={{flex:1,display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",gap:4,border:"none",background:"transparent",cursor:"pointer",padding:"8px 2px",position:"relative"}}>
        {moreActive&&!drawerOpen&&<div style={{position:"absolute",top:0,width:22,height:3,borderRadius:"0 0 3px 3px",background:BLUE_ON}}/>}
        <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke={drawerOpen||moreActive?"#fff":"rgba(255,255,255,0.5)"} strokeWidth="2"><circle cx="5" cy="12" r="1.6" fill="currentColor"/><circle cx="12" cy="12" r="1.6" fill="currentColor"/><circle cx="19" cy="12" r="1.6" fill="currentColor"/></svg>
        <span style={{fontSize:9.5,color:drawerOpen||moreActive?"#fff":"rgba(255,255,255,0.5)",fontWeight:600,lineHeight:1}}>Ещё</span>
      </button>
    </div>

    {/* Drawer overlay */}
    {drawerOpen&&<div style={{position:"fixed",inset:0,zIndex:190,background:"rgba(0,0,0,0.5)"}} onClick={()=>setDrawerOpen(false)}/>}

    {/* Drawer panel */}
    <div style={{position:"fixed",bottom:62,left:0,right:0,background:C.dk,zIndex:195,borderTop:"1px solid rgba(255,255,255,0.1)",borderRadius:"20px 20px 0 0",transform:drawerOpen?"translateY(0)":"translateY(110%)",transition:"transform 0.3s ease",maxHeight:"70vh",overflowY:"auto",paddingBottom:"env(safe-area-inset-bottom)"}}>
      <div style={{padding:"12px 0 4px",textAlign:"center"}}>
        <div style={{width:36,height:4,background:"rgba(255,255,255,0.15)",borderRadius:2,margin:"0 auto"}}/>
      </div>
      <div style={{padding:"6px 18px 10px",fontSize:11,fontWeight:700,letterSpacing:1,color:"rgba(255,255,255,0.35)",textTransform:"uppercase"}}>Все разделы</div>
      <div style={{padding:"0 16px 16px",display:"grid",gridTemplateColumns:"1fr 1fr",gap:8}}>
        {more.map(n=>{
          const a=active===n.id;
          return <button key={n.id} onClick={()=>{onNav(n.id);setDrawerOpen(false);}}
            style={{display:"flex",alignItems:"center",gap:10,padding:"12px 14px",border:"none",borderRadius:10,background:a?"#2563EB":"rgba(255,255,255,0.07)",cursor:"pointer"}}>
            <I path={n.ic} size={18} color={a?"#fff":"rgba(255,255,255,0.7)"}/>
            <span style={{fontSize:13,color:a?"#fff":"rgba(255,255,255,0.7)",fontWeight:a?600:400,textAlign:"left",lineHeight:1.2}}>{n.label}</span>
          </button>;
        })}
        <button onClick={()=>{onLogout();setDrawerOpen(false);}}
          style={{display:"flex",alignItems:"center",gap:10,padding:"12px 14px",border:"none",borderRadius:10,background:"rgba(119,119,119,0.15)",cursor:"pointer",gridColumn:"span 2"}}>
          <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="#777777" strokeWidth="1.5"><path d="M9 21H5a2 2 0 01-2-2V5a2 2 0 012-2h4"/><polyline points="16 17 21 12 16 7"/><line x1="21" y1="12" x2="9" y2="12"/></svg>
          <span style={{fontSize:13,color:"#777777",fontWeight:500}}>Выйти</span>
        </button>
      </div>
    </div>
  </>;
}

const Head=({name,onMenuOpen}:{name:string,onMenuOpen?:()=>void})=>{
  const isMobile=useIsMobile();
  const{dark}=useTheme();
  const greeting = getGreeting();
  const displayName = name && name !== "User" ? name : "";
  if(isMobile) return <div style={{height:56,background:C.dk,display:"flex",alignItems:"center",justifyContent:"space-between",padding:"0 16px",position:"sticky",top:0,zIndex:50}}>
    <div style={{display:"flex",alignItems:"center",gap:10}}>
      <Logo s={34}/>
      <div style={{display:"flex",flexDirection:"column",lineHeight:1.15}}>
        <span style={{color:"#fff",fontSize:11,fontWeight:800,letterSpacing:1.5}}>VIZZY</span>
        <span style={{color:"rgba(255,255,255,0.4)",fontSize:8,letterSpacing:1}}>by Kirill Scales</span>
      </div>
    </div>
    <div style={{fontSize:13,fontWeight:500,color:"rgba(255,255,255,0.7)"}}>{greeting}{displayName?", "+displayName:""}</div>
  </div>;
  return <div style={{
    height:64,
    background:dark
      ?"rgba(14,14,14,0.85)"
      :C.w,
    backdropFilter:dark?"blur(24px)":"none",
    WebkitBackdropFilter:dark?"blur(24px)":"none",
    borderBottom:`1px solid ${dark?"rgba(255,255,255,0.05)":C.bd}`,
    display:"flex",alignItems:"center",justifyContent:"space-between",
    padding:"0 32px",position:"sticky",top:0,zIndex:50,
    boxShadow:dark?"0 1px 0 rgba(255,255,255,0.03), 0 4px 20px rgba(0,0,0,0.3)":"none",
  }}>
    <div style={{fontSize:15,fontWeight:600,color:C.t1}}>{greeting}{displayName?", "+displayName:""}</div>
    <div style={{display:"inline-flex",alignItems:"center",gap:10,
      background:dark?"rgba(255,255,255,0.04)":"#1F1F1F",
      border:dark?"1px solid rgba(255,255,255,0.08)":"none",
      padding:"8px 20px",borderRadius:8,
      boxShadow:dark?"inset 0 1px 0 rgba(255,255,255,0.04)":"none",
    }}>
      <Logo s={28}/>
      <div style={{display:"flex",flexDirection:"column",lineHeight:1.15}}>
        <span style={{color:"#fff",fontSize:11,fontWeight:800,letterSpacing:1.5}}>VIZZY</span>
        <span style={{color:"rgba(255,255,255,0.5)",fontSize:8,fontWeight:300,letterSpacing:1}}>by Kirill Scales</span>
      </div>
    </div>
    <div style={{fontSize:13,color:C.t2}}>{fmtDate(new Date())}</div>
  </div>;
};

const Placeholder=({title,ic}:{title:string,ic:string})=><div style={{display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",height:"calc(100vh - 180px)",gap:20}}><div style={{width:80,height:80,borderRadius:10,background:C.a+"18",display:"flex",alignItems:"center",justifyContent:"center"}}><I path={ic} size={36} color={C.a} sw={1.2}/></div><div style={{fontSize:22,fontWeight:700}}>{title}</div><Card style={{padding:"12px 24px"}}><span style={{fontSize:14,color:C.t2}}>Раздел скоро будет доступен</span></Card></div>;

/* ============ MAIN APP ============ */
export default function App() {
  const [user, setUser] = useState<any>(null);
  const APP_VERSION="v2.2"; // bump this to force-clear stale localStorage
  const VALID_PAGES=["dashboard","strategy","crm","calls","content","forms","offer","prices","icp","bizstrategy","team","links","profile","files","ai","script","product","stories","pnl","media","ads","calc","tools","mailings"];

  // Clear stale localStorage on version change
  useEffect(()=>{
    try{
      const storedVersion=localStorage.getItem("ff_version");
      if(storedVersion!==APP_VERSION){
        localStorage.removeItem("ff_page");
        localStorage.setItem("ff_version",APP_VERSION);
      }
    }catch{}
  },[]);

  const [page, setPage] = useState(()=>{
    try{
      // Check version first
      const storedVersion=localStorage.getItem("ff_version");
      if(storedVersion!==APP_VERSION)return "dashboard";
      const saved=localStorage.getItem("ff_page")||"dashboard";
      if(!VALID_PAGES.includes(saved)){
        localStorage.removeItem("ff_page");
        return "dashboard";
      }
      return saved;
    }catch{return "dashboard";}
  });

  useEffect(()=>{
    try{localStorage.setItem("ff_page",page);}catch{}
  },[page]);
  const [loading, setLoading] = useState(true);
  const [userName, setUserName] = useState("");
  const [userAvatar, setUserAvatar] = useState("");
  const [dark, setDark] = useState<boolean>(()=>{
    try{return localStorage.getItem("ff_theme")==="dark";}catch{return false;}
  });

  // Apply theme tokens + body class
  useEffect(()=>{
    applyTheme(dark);
    document.body.classList.toggle("dark",dark);
    try{localStorage.setItem("ff_theme",dark?"dark":"light");}catch{}
  },[dark]);

  const toggleTheme=()=>setDark(d=>!d);

  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      if (session?.user) { setUser(session.user); loadProfile(session.user.id); }
      setLoading(false);
    });
    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      if (session?.user) { setUser(session.user); loadProfile(session.user.id); }
      else { setUser(null); }
    });
    return () => subscription.unsubscribe();
  }, []);

  const loadProfile = async (uid: string) => {
    const { data } = await supabase.from("profiles").select("name,avatar_url").eq("id", uid).single();
    if (data?.name) setUserName(data.name);
    if (data?.avatar_url) setUserAvatar(data.avatar_url);
  };

  const logout = async () => {
    await supabase.auth.signOut();
    setUser(null);
    setPage("dashboard");
  };

  if (loading) return <div style={{minHeight:"100vh",display:"flex",alignItems:"center",justifyContent:"center",background:C.bg,fontFamily:"'Inter',sans-serif"}}><div style={{fontSize:18,color:C.t2}}>Загрузка...</div></div>;
  if (!user) return <Auth onLogin={(u) => { setUser(u); loadProfile(u.id); }} />;

  const nav = NAV.find(n => n.id === page);

  return(
    <ThemeCtx.Provider value={{dark,toggle:toggleTheme}}>
      <AppLayout user={user} page={page} setPage={setPage} userName={userName} setUserName={setUserName} userAvatar={userAvatar} setUserAvatar={setUserAvatar} logout={logout} nav={nav} dark={dark}/>
    </ThemeCtx.Provider>
  );
}

// ── Error boundary for pages ──────────────────────────────
class PageErrorBoundary extends React.Component<{children:React.ReactNode,name:string},{err:Error|null}>{
  constructor(p:any){super(p);this.state={err:null};}
  static getDerivedStateFromError(e:Error){return{err:e};}
  render(){
    if(this.state.err)return(
      <div style={{padding:40,textAlign:"center"}}>
        <div style={{fontSize:32,marginBottom:12}}>⚠️</div>
        <div style={{fontSize:18,fontWeight:700,marginBottom:8,color:"#777777"}}>Ошибка в разделе {this.props.name}</div>
        <div style={{fontSize:12,color:"#727272",marginBottom:20,fontFamily:"monospace",maxWidth:600,margin:"0 auto 20px"}}>{this.state.err.message}</div>
        <button onClick={()=>this.setState({err:null})} style={{padding:"10px 20px",background:"#606060",color:"#fff",border:"none",borderRadius:8,cursor:"pointer",fontSize:14,fontWeight:600}}>Обновить раздел</button>
      </div>
    );
    return this.props.children;
  }
}

function SafePage({name,children}:{name:string,children:React.ReactNode}){
  return<PageErrorBoundary name={name}>{children}</PageErrorBoundary>;
}

