const KS_STAGE_LABELS:Record<string,string>={idea:"Идея",progress:"Разработка",ready:"Реализация",published:"Опубликовано"};
const ksFire=(t:string)=>{try{window.dispatchEvent(new CustomEvent("ks-refresh",{detail:{table:t}}));}catch{}};

async function ksExecTool(name:string,a:any,userId:string):Promise<string>{
  if(!userId)return "Ошибка: пользователь не определён.";
  try{
    if(name==="create_lead"){
      const row:any={name:a.name||"Без имени",contact:a.contact||"",phone:a.phone||"",email:a.email||"",source:a.source||"Instagram",status:a.status||"new",note:a.note||"",deal:a.deal||"",pains:"",desires:"",objections:"",leverage:"",next_step:a.next_step||"",ai_report:"",avatar_url:"",user_id:userId};
      const{data,error}=await supabase.from("leads").insert(row).select().single();
      if(error)return "Ошибка создания лида: "+error.message;
      ksFire("leads");
      const st=(CRM_DEFAULT_STAGES.find(s=>s.id===row.status)||{label:row.status}).label;
      return `Лид «${row.name}» добавлен в CRM (стадия «${st}»).`;
    }
    if(name==="list_leads"){
      let q=supabase.from("leads").select("*").eq("user_id",userId);
      if(a.status)q=q.eq("status",a.status);
      const{data}=await q.order("created_at",{ascending:false}).limit(50);
      if(!data||!data.length)return a.status?"Лидов на этой стадии нет.":"Лидов пока нет.";
      return `Лидов ${data.length}: `+data.map((l:any)=>`${l.name}${l.deal?" ("+l.deal+")":""} [${(CRM_DEFAULT_STAGES.find(s=>s.id===l.status)||{label:l.status}).label}]${l.next_step?" → "+l.next_step:""}`).join("; ");
    }
    if(name==="create_funnel"){
      const{data,error}=await supabase.from("crm_funnels").insert({name:a.name||"Новая воронка",description:a.description||"",color:FUNNEL_COLORS[0],user_id:userId}).select().single();
      if(error)return "Ошибка создания воронки: "+error.message;
      ksFire("crm_funnels");
      return `Воронка продаж «${a.name||"Новая воронка"}» создана в CRM.`;
    }
    if(name==="create_task"){
      const row:any={title:a.title||"Задача",description:a.description||"",due_date:a.due_date||"",due_time:"",priority:a.priority||"none",color:"#3B82F6",done:false,subtasks:[],user_id:userId,updated_at:new Date().toISOString()};
      const{data,error}=await supabase.from("planner_tasks").insert(row).select().single();
      if(error)return "Ошибка создания задачи: "+error.message;
      ksFire("planner_tasks");
      return `Задача «${row.title}» добавлена в планер${row.due_date?" на "+row.due_date:""}${row.priority!=="none"?", приоритет "+row.priority:""}.`;
    }
    if(name==="list_tasks"){
      const{data}=await supabase.from("planner_tasks").select("*").eq("user_id",userId).eq("done",false).order("due_date",{ascending:true}).limit(50);
      if(!data||!data.length)return "Активных задач нет.";
      return `Активных задач ${data.length}: `+data.map((t:any)=>`${t.title}${t.due_date?" ("+t.due_date+")":""}`).join("; ");
    }
    if(name==="create_script"){
      const kind=a.kind==="long"?"long":"short";
      const{data:sc,error}=await supabase.from("scripts").insert({name:a.name||"Новый сценарий",kind,content:a.content||"",icp:"",versions:[],chat:[],user_id:userId,updated_at:new Date().toISOString()}).select().single();
      if(error)return "Ошибка создания сценария: "+error.message;
      let extra="";
      if(a.to_kanban&&sc){
        const{data:card}=await supabase.from("content").insert({platform:"telegram",type:"Сценарий",topic:sc.name,status:"progress",scenario:sc.content,script_id:sc.id,user_id:userId}).select().single();
        if(card){await supabase.from("scripts").update({content_id:card.id}).eq("id",sc.id);extra=" и добавлен карточкой в «Разработку» на Канбане";}
        ksFire("content");
      }
      ksFire("scripts");
      return `Сценарий «${a.name||"Новый сценарий"}» создан в разделе Контент${extra}.`;
    }
    if(name==="create_content_card"){
      const{data,error}=await supabase.from("content").insert({platform:a.platform||"telegram",type:a.type||"Пост",topic:a.title||"Карточка",status:a.stage||"idea",scenario:a.scenario||"",user_id:userId}).select().single();
      if(error)return "Ошибка создания карточки: "+error.message;
      ksFire("content");
      return `Карточка «${a.title||"Карточка"}» добавлена в Контент (${KS_STAGE_LABELS[a.stage||"idea"]||"Идея"}).`;
    }
    /* ── Общий срез ── */
    if(name==="get_overview"){
      const now=new Date();const t0=ds(now);const t1=ds(new Date(now.getTime()+86400000));
      const monthPrefix=t0.slice(0,7);
      const[leadsR,tasksR,calR,callsR,pnlR]=await Promise.all([
        supabase.from("leads").select("status").eq("user_id",userId),
        supabase.from("planner_tasks").select("title,due_date").eq("user_id",userId).eq("done",false),
        supabase.from("planner_tasks").select("title,due_date,due_time").eq("user_id",userId).eq("done",false).in("due_date",[t0,t1]),
        supabase.from("calls").select("title,date,time_start").eq("user_id",userId).gte("date",t0).order("date",{ascending:true}).limit(5),
        supabase.from("pnl").select("type,amount,date").eq("user_id",userId).like("date",monthPrefix+"%"),
      ]);
      const byStage:Record<string,number>={};(leadsR.data||[]).forEach((l:any)=>{byStage[l.status]=(byStage[l.status]||0)+1;});
      const stageStr=CRM_DEFAULT_STAGES.map(s=>byStage[s.id]?`${s.label}: ${byStage[s.id]}`:null).filter(Boolean).join(", ")||"нет лидов";
      const tasks=tasksR.data||[];
      const today0=(calR.data||[]).filter((t:any)=>t.due_date===t0).sort((x:any,y:any)=>(x.due_time||"").localeCompare(y.due_time||""));
      const tmrw=(calR.data||[]).filter((t:any)=>t.due_date===t1).sort((x:any,y:any)=>(x.due_time||"").localeCompare(y.due_time||""));
      const inc=(pnlR.data||[]).filter((p:any)=>p.type==="income").reduce((s:number,p:any)=>s+(+p.amount||0),0);
      const exp=(pnlR.data||[]).filter((p:any)=>p.type==="expense").reduce((s:number,p:any)=>s+(+p.amount||0),0);
      const calls=(callsR.data||[]);
      return [
        `CRM: ${leadsR.data?.length||0} лидов (${stageStr}).`,
        `War Room: ${tasks.length} активных задач${tasks.length?" — "+tasks.slice(0,5).map((t:any)=>t.title).join(", "):""}.`,
        `Расписание сегодня (${t0}): ${today0.length?today0.map((t:any)=>`${t.due_time||"—"} ${t.title}`).join("; "):"пусто"}.`,
        `Расписание завтра (${t1}): ${tmrw.length?tmrw.map((t:any)=>`${t.due_time||"—"} ${t.title}`).join("; "):"пусто"}.`,
        `Созвоны: ${calls.length?calls.map((c:any)=>`${c.date} ${c.time_start||""} ${c.title}`.trim()).join("; "):"нет запланированных"}.`,
        `Финансы за месяц: доход ${inc.toLocaleString("ru-RU")} ₽, расход ${exp.toLocaleString("ru-RU")} ₽, прибыль ${(inc-exp).toLocaleString("ru-RU")} ₽.`,
      ].join("\n");
    }

    /* ── CRM ── */
    if(name==="update_lead"){
      const{data:found}=await supabase.from("leads").select("*").eq("user_id",userId).ilike("name",`%${a.name}%`).order("created_at",{ascending:false}).limit(1);
      const lead=found?.[0];
      if(!lead)return `Лид «${a.name}» не найден.`;
      const upd:any={};
      if(a.status)upd.status=a.status;
      if(a.next_step!==undefined)upd.next_step=a.next_step;
      if(a.note!==undefined)upd.note=a.note;
      if(a.deal!==undefined)upd.deal=a.deal;
      if(a.phone!==undefined)upd.phone=a.phone;
      if(a.contact!==undefined)upd.contact=a.contact;
      if(!Object.keys(upd).length)return "Нечего обновлять — не переданы изменения.";
      const{error}=await supabase.from("leads").update(upd).eq("id",lead.id);
      if(error)return "Ошибка обновления лида: "+error.message;
      ksFire("leads");
      const parts:string[]=[];
      if(upd.status)parts.push(`стадия → «${(CRM_DEFAULT_STAGES.find(s=>s.id===upd.status)||{label:upd.status}).label}»`);
      if(upd.next_step)parts.push(`следующий шаг → «${upd.next_step}»`);
      if(upd.deal)parts.push(`сделка → ${upd.deal}`);
      return `Лид «${lead.name}» обновлён${parts.length?": "+parts.join(", "):""}.`;
    }
    if(name==="list_funnels"){
      const{data}=await supabase.from("crm_funnels").select("*").eq("user_id",userId).order("created_at",{ascending:false});
      if(!data||!data.length)return "Воронок пока нет.";
      return `Воронки (${data.length}): `+data.map((f:any)=>f.name).join("; ");
    }

    /* ── War Room ── */
    if(name==="complete_task"){
      const{data:found}=await supabase.from("planner_tasks").select("*").eq("user_id",userId).eq("done",false).ilike("title",`%${a.title}%`).order("created_at",{ascending:false}).limit(1);
      const task=found?.[0];
      if(!task)return `Активная задача «${a.title}» не найдена.`;
      const{error}=await supabase.from("planner_tasks").update({done:true,updated_at:new Date().toISOString()}).eq("id",task.id);
      if(error)return "Ошибка: "+error.message;
      ksFire("planner_tasks");
      return `Задача «${task.title}» отмечена выполненной.`;
    }

    /* ── Расписание = задачи War Room (planner_tasks) + спринт + цели ── */
    if(name==="get_schedule"){
      const from=a.date;const to=a.date_to||a.date;
      if(!from)return "Не указана дата.";
      const[plR,kbR,gtR]=await Promise.all([
        supabase.from("planner_tasks").select("title,due_date,due_time,done").eq("user_id",userId).gte("due_date",from).lte("due_date",to),
        supabase.from("kanban").select("text,date,start_time,done").eq("user_id",userId).gte("date",from).lte("date",to),
        supabase.from("goal_tasks").select("text,date,start_time,done").eq("user_id",userId).gte("date",from).lte("date",to),
      ]);
      const rows:any[]=[];
      (plR.data||[]).forEach((t:any)=>rows.push({date:t.due_date,start:t.due_time||"—",text:t.title,done:t.done,tag:""}));
      (kbR.data||[]).filter((t:any)=>t.date).forEach((t:any)=>rows.push({date:t.date,start:t.start_time||"10:00",text:t.text,done:t.done,tag:" (спринт)"}));
      (gtR.data||[]).filter((t:any)=>t.date).forEach((t:any)=>rows.push({date:t.date,start:t.start_time||"10:00",text:t.text,done:t.done,tag:" (цель)"}));
      if(!rows.length)return `На ${from===to?from:from+"–"+to} задач в расписании нет.`;
      rows.sort((x,y)=>x.date===y.date?(x.start||"").localeCompare(y.start||""):x.date.localeCompare(y.date));
      const byDate:Record<string,string[]>={};
      rows.forEach(r=>{(byDate[r.date]=byDate[r.date]||[]).push(`${r.start} ${r.text}${r.tag}${r.done?" ✓":""}`);});
      return Object.keys(byDate).map(d=>`${d}:\n  `+byDate[d].join("\n  ")).join("\n");
    }
    if(name==="add_schedule_item"){
      const row:any={title:a.text||"Дело",description:a.description||"",due_date:a.date||today(),due_time:a.start_time||"10:00",priority:"none",color:"#3B82F6",done:false,subtasks:[],user_id:userId,updated_at:new Date().toISOString()};
      const{error}=await supabase.from("planner_tasks").insert(row).select().single();
      if(error)return "Ошибка добавления в расписание: "+error.message;
      ksFire("planner_tasks");
      return `«${row.title}» добавлено в расписание (War Room) на ${row.due_date} ${row.due_time}.`;
    }
    if(name==="build_day_schedule"){
      const date=a.date||today();
      const items=Array.isArray(a.items)?a.items:[];
      if(!items.length)return "Не переданы блоки расписания.";
      const rows=items.map((it:any)=>({title:it.text||"Дело",description:it.description||(it.end_time?`до ${it.end_time}`:""),due_date:date,due_time:it.start_time||"10:00",priority:"none",color:"#3B82F6",done:false,subtasks:[],user_id:userId,updated_at:new Date().toISOString()}));
      const{data,error}=await supabase.from("planner_tasks").insert(rows).select();
      if(error)return "Ошибка построения расписания: "+error.message;
      ksFire("planner_tasks");
      const list=(data||rows).map((r:any)=>`${r.due_time} ${r.title}`).join(", ");
      return `Расписание на ${date} составлено — ${rows.length} задач в War Room: ${list}. Смотри «War Room → Календарь задач».`;
    }
    if(name==="update_schedule_item"){
      let q=supabase.from("planner_tasks").select("*").eq("user_id",userId).ilike("title",`%${a.text}%`);
      if(a.on_date)q=q.eq("due_date",a.on_date);
      const{data:found}=await q.order("created_at",{ascending:false}).limit(1);
      const item=found?.[0];
      if(!item)return `Задача «${a.text}» не найдена.`;
      const upd:any={updated_at:new Date().toISOString()};
      if(a.new_text)upd.title=a.new_text;
      if(a.new_date)upd.due_date=a.new_date;
      if(a.start_time)upd.due_time=a.start_time;
      const{error}=await supabase.from("planner_tasks").update(upd).eq("id",item.id);
      if(error)return "Ошибка обновления: "+error.message;
      ksFire("planner_tasks");
      return `Задача «${item.title}» обновлена${upd.due_date?` → ${upd.due_date}`:""}${upd.due_time?` ${upd.due_time}`:""}.`;
    }
    if(name==="remove_schedule_item"){
      let q=supabase.from("planner_tasks").select("*").eq("user_id",userId).ilike("title",`%${a.text}%`);
      if(a.on_date)q=q.eq("due_date",a.on_date);
      const{data:found}=await q.order("created_at",{ascending:false}).limit(1);
      const item=found?.[0];
      if(!item)return `Задача «${a.text}» не найдена.`;
      const{error}=await supabase.from("planner_tasks").delete().eq("id",item.id);
      if(error)return "Ошибка удаления: "+error.message;
      ksFire("planner_tasks");
      return `Задача «${item.title}» (${item.due_date||"без даты"}) удалена из расписания.`;
    }

    /* ── Спринт и цели ── */
    if(name==="create_sprint_task"){
      const row:any={title:a.text||"Задача",description:a.type?`Тип: ${a.type}${a.mins?` · ${a.mins} мин`:""}`:"",due_date:a.date||null,due_time:"",priority:"none",color:"#3B82F6",done:false,subtasks:[],user_id:userId,updated_at:new Date().toISOString()};
      const{error}=await supabase.from("planner_tasks").insert(row).select().single();
      if(error)return "Ошибка создания задачи: "+error.message;
      ksFire("planner_tasks");
      return `Задача «${row.title}» добавлена в War Room${row.due_date?" на "+row.due_date:""}.`;
    }
    if(name==="create_goal"){
      const{data:pinned}=await supabase.from("goals").select("id").eq("user_id",userId).eq("is_system_pinned",true).limit(1);
      const parentId=pinned?.[0]?.id||null;
      const row:any={name:a.name||"Новая цель",description:a.description||"",color:C.a,start_date:null,end_date:a.deadline||null,deadline:a.deadline||null,parent_id:parentId,is_system_pinned:false,user_id:userId};
      const{error}=await supabase.from("goals").insert(row).select().single();
      if(error)return "Ошибка создания цели: "+error.message;
      ksFire("goals");
      return `Цель «${row.name}» добавлена в раздел Цели${row.deadline?" (дедлайн "+row.deadline+")":""}.`;
    }
    if(name==="list_goals"){
      const{data}=await supabase.from("goals").select("*").eq("user_id",userId).eq("is_system_pinned",false).order("created_at",{ascending:false}).limit(50);
      if(!data||!data.length)return "Целей пока нет.";
      return `Цели (${data.length}): `+data.map((g:any)=>`${g.name}${g.deadline?" (до "+g.deadline+")":""}`).join("; ");
    }

    /* ── Созвоны ── */
    if(name==="create_call"){
      const start=a.time_start||"10:00";
      const end=a.time_end||(()=>{const[h,m]=start.split(":").map(Number);return String((h+1)%24).padStart(2,"0")+":"+String(m).padStart(2,"0");})();
      const goal=a.goal||"Созвон с лидом";
      const row:any={title:a.title||"Созвон",date:a.date||today(),time_start:start,time_end:end,goal,custom_goal:goal==="Своя цель"?(a.title||""):"",setter_name:"",responsible_name:"",link:a.link||"",description:a.description||"",user_id:userId};
      const{error}=await supabase.from("calls").insert(row).select().single();
      if(error)return "Ошибка создания созвона: "+error.message;
      ksFire("calls");
      return `Созвон «${row.title}» запланирован на ${row.date} ${row.time_start}–${row.time_end}.`;
    }
    if(name==="list_calls"){
      const{data}=await supabase.from("calls").select("*").eq("user_id",userId).gte("date",today()).order("date",{ascending:true}).limit(30);
      if(!data||!data.length)return "Ближайших созвонов нет.";
      return `Созвоны (${data.length}): `+data.map((c:any)=>`${c.date} ${c.time_start||""} ${c.title||c.goal}`.trim()).join("; ");
    }

    /* ── Контент ── */
    if(name==="list_content"){
      let q=supabase.from("content").select("*").eq("user_id",userId);
      if(a.stage)q=q.eq("status",a.stage);
      const{data}=await q.order("created_at",{ascending:false}).limit(50);
      if(!data||!data.length)return "Карточек контента нет.";
      return `Контент (${data.length}): `+data.map((c:any)=>`${c.topic||c.type} [${KS_STAGE_LABELS[c.status]||c.status}]`).join("; ");
    }

    /* ── Финансы ── */
    if(name==="add_transaction"){
      const amt=+a.amount||0;
      if(amt<=0)return "Сумма должна быть больше нуля.";
      const row:any={type:a.type==="expense"?"expense":"income",amount:amt,category:a.category||(a.type==="expense"?"Прочее":"Продажи"),date:a.date||today(),comment:a.comment||"",user_id:userId};
      const{error}=await supabase.from("pnl").insert(row).select().single();
      if(error)return "Ошибка внесения транзакции: "+error.message;
      ksFire("pnl");
      return `${row.type==="income"?"Доход":"Расход"} ${amt.toLocaleString("ru-RU")} ₽ (${row.category}) внесён в Финансы на ${row.date}.`;
    }
    if(name==="get_finance"){
      const month=a.month||today().slice(0,7);
      const{data}=await supabase.from("pnl").select("*").eq("user_id",userId).like("date",month+"%");
      if(!data||!data.length)return `За ${month} транзакций нет.`;
      const inc=data.filter((p:any)=>p.type==="income").reduce((s:number,p:any)=>s+(+p.amount||0),0);
      const exp=data.filter((p:any)=>p.type==="expense").reduce((s:number,p:any)=>s+(+p.amount||0),0);
      const catMap:Record<string,number>={};
      data.forEach((p:any)=>{const k=(p.type==="income"?"+ ":"- ")+(p.category||"Прочее");catMap[k]=(catMap[k]||0)+(+p.amount||0);});
      const cats=Object.entries(catMap).map(([k,v])=>`${k}: ${v.toLocaleString("ru-RU")} ₽`).join(", ");
      return `Финансы за ${month}: доход ${inc.toLocaleString("ru-RU")} ₽, расход ${exp.toLocaleString("ru-RU")} ₽, прибыль ${(inc-exp).toLocaleString("ru-RU")} ₽. Категории: ${cats}.`;
    }

    return "Неизвестный инструмент: "+name;
  }catch(e:any){return "Ошибка выполнения: "+(e?.message||String(e));}
}

const kirillAIStore=(()=>{
  let chats:KSChat[]=[];
  let activeId:string="";
  let hydrated=false;
  let lastPersist=0;
  const generating=new Set<string>();
  const aborts=new Map<string,AbortController>();
  const listeners=new Set<()=>void>();
  let uidUser="";

  const uid=(p:string)=>p+Date.now().toString(36)+Math.random().toString(36).slice(2,6);
  const blank=():KSChat=>({id:uid("c"),title:"Новый чат",messages:[],createdAt:Date.now(),updatedAt:Date.now()});
  const emit=()=>{listeners.forEach(l=>{try{l();}catch{}});};

  const persist=(force=false)=>{
    if(typeof window==="undefined")return;
    const now=Date.now();
    if(!force&&now-lastPersist<500)return;
    lastPersist=now;
    try{
      localStorage.setItem(KS_AI_KEY,JSON.stringify(chats));
      localStorage.setItem(KS_AI_ACTIVE_KEY,activeId);
    }catch{}
  };

  const hydrate=()=>{
    if(hydrated)return;
    if(typeof window==="undefined"){
      if(!chats.length){const c=blank();chats=[c];activeId=c.id;}
      return; // не помечаем hydrated — дочитаем на клиенте
    }
    hydrated=true;
    try{
      const raw=localStorage.getItem(KS_AI_KEY);
      if(raw){const p=JSON.parse(raw);if(Array.isArray(p))chats=p;}
      activeId=localStorage.getItem(KS_AI_ACTIVE_KEY)||"";
    }catch{}
    if(!chats.length){const c=blank();chats=[c];activeId=c.id;}
    if(!chats.find(c=>c.id===activeId))activeId=chats[0].id;
  };

  const patch=(id:string,fn:(c:KSChat)=>KSChat)=>{chats=chats.map(c=>c.id===id?fn(c):c);};

  const run=async(chatId:string)=>{
    const target=chats.find(c=>c.id===chatId);
    if(!target)return;
    const aiMsg=target.messages[target.messages.length-1];
    if(!aiMsg||aiMsg.role!=="assistant")return;
    const aiId=aiMsg.id;
    const history=target.messages.filter(m=>m.id!==aiId).map(m=>({role:m.role,content:m.content}));

    const ctrl=new AbortController();
    aborts.set(chatId,ctrl);
    generating.add(chatId);
    emit();

    const setAI=(content:string,force=false)=>{
      patch(chatId,c=>({...c,updatedAt:Date.now(),messages:c.messages.map(m=>m.id===aiId?{...m,content}:m)}));
      persist(force);emit();
    };

    try{
      const msgs:any[]=[{role:"system",content:KIRILL_AI_SYSTEM+"\n\n"+KS_ACTIONS_NOTE+"\n\n"+ksDateContext()},...history];
      let finalText="";
      for(let step=0;step<10;step++){
        const res=await fetch("https://api.deepseek.com/v1/chat/completions",{
          method:"POST",signal:ctrl.signal,
          headers:{"Content-Type":"application/json","Authorization":`Bearer ${process.env.NEXT_PUBLIC_DEEPSEEK_API_KEY}`},
          body:JSON.stringify({model:"deepseek-chat",max_tokens:2000,messages:msgs,tools:KS_TOOLS,tool_choice:"auto"}),
        });
        const data=await res.json();
        const msg=data.choices?.[0]?.message;
        if(!msg){finalText="Не удалось получить ответ.";break;}
        if(msg.tool_calls&&msg.tool_calls.length){
          msgs.push(msg);
          for(const tc of msg.tool_calls){
            let args:any={};try{args=JSON.parse(tc.function?.arguments||"{}");}catch{}
            setAI("Выполняю…");
            const result=await ksExecTool(tc.function?.name,args,uidUser);
            msgs.push({role:"tool",tool_call_id:tc.id,content:result});
          }
          continue;
        }
        finalText=stripMd(msg.content||"Готово.");break;
      }
      setAI(finalText||"Готово.",true);
    }catch(e:any){
      if(e?.name!=="AbortError"){setAI("Ошибка соединения. Проверь API-ключ или попробуй ещё раз.",true);}
    }finally{
      generating.delete(chatId);
      aborts.delete(chatId);
      persist(true);emit();
    }
  };

  return{
    subscribe(l:()=>void){hydrate();listeners.add(l);return()=>{listeners.delete(l);};},
    setUser(id:string){uidUser=id;},
    getChats(){hydrate();return chats;},
    getActiveId(){hydrate();return activeId;},
    getActive(){hydrate();return chats.find(c=>c.id===activeId)||chats[0];},
    isGenerating(id:string){return generating.has(id);},
    setActive(id:string){hydrate();activeId=id;persist(true);emit();},
    createChat(){hydrate();const c=blank();chats=[c,...chats];activeId=c.id;persist(true);emit();return c.id;},
    deleteChat(id:string){
      hydrate();
      aborts.get(id)?.abort();aborts.delete(id);generating.delete(id);
      chats=chats.filter(c=>c.id!==id);
      if(!chats.length){const c=blank();chats=[c];activeId=c.id;}
      else if(activeId===id)activeId=chats[0].id;
      persist(true);emit();
    },
    clearActive(){
      hydrate();
      const id=activeId;
      aborts.get(id)?.abort();aborts.delete(id);generating.delete(id);
      patch(id,c=>({...c,messages:[],title:"Новый чат",updatedAt:Date.now()}));
      persist(true);emit();
    },
    stop(id:string){aborts.get(id)?.abort();aborts.delete(id);generating.delete(id);emit();},
    send(text:string){
      hydrate();
      const t=text.trim();
      if(!t)return;
      const id=activeId;
      const chat=chats.find(c=>c.id===id);
      if(!chat)return;
      const userMsg:ChatMessage={role:"user",content:t,id:uid("u")};
      const aiMsg:ChatMessage={role:"assistant",content:"",id:uid("a")};
      const first=chat.messages.length===0;
      patch(id,c=>({...c,title:first?(t.length>42?t.slice(0,42)+"…":t):c.title,messages:[...c.messages,userMsg,aiMsg],updatedAt:Date.now()}));
      persist(true);emit();
      run(id);
    },
  };
})();

const KS_AI_LOGO="/icon-ai.png";

function KirillAIPage({userId}:{userId:string}){
  const{dark}=useTheme();
  const isMobile=useIsMobile();
  const[mounted,setMounted]=useState(false);
  const[,setTick]=useState(0);

  useEffect(()=>{
    setMounted(true);
    kirillAIStore.setUser(userId);
    const unsub=kirillAIStore.subscribe(()=>setTick(t=>t+1));
    return unsub;
  },[userId]);

  const chats=kirillAIStore.getChats();
  const activeId=kirillAIStore.getActiveId();
  const activeChat=kirillAIStore.getActive();
  const messages=activeChat?.messages||[];
  const loading=activeChat?kirillAIStore.isGenerating(activeChat.id):false;

  const[input,setInput]=useState("");
  const[copiedId,setCopiedId]=useState<string|null>(null);
  const[hoveredId,setHoveredId]=useState<string|null>(null);
  const[hoverChat,setHoverChat]=useState<string|null>(null);
  const[showList,setShowList]=useState(true);
  const endRef=useRef<HTMLDivElement>(null);
  const inputRef=useRef<HTMLTextAreaElement>(null);

  useEffect(()=>{setShowList(!isMobile);},[isMobile]);
  useEffect(()=>{endRef.current?.scrollIntoView({behavior:"smooth"});},[messages,loading,activeId]);

  const send=()=>{
    const text=input.trim();
    if(!text||loading)return;
    setInput("");
    if(inputRef.current)inputRef.current.style.height="auto";
    requestAnimationFrame(()=>inputRef.current?.focus());
    kirillAIStore.send(text);
  };
  const stop=()=>{if(activeChat)kirillAIStore.stop(activeChat.id);};
  const clear=()=>{if(confirm("Очистить весь диалог?"))kirillAIStore.clearActive();};
  const newChat=()=>{kirillAIStore.createChat();setInput("");if(isMobile)setShowList(false);requestAnimationFrame(()=>inputRef.current?.focus());};
  const pickChat=(id:string)=>{kirillAIStore.setActive(id);if(isMobile)setShowList(false);};
  const removeChat=(id:string,e:React.MouseEvent)=>{e.stopPropagation();if(confirm("Удалить этот чат?"))kirillAIStore.deleteChat(id);};

  const copyMsg=(content:string,id:string)=>{
    navigator.clipboard.writeText(content);
    setCopiedId(id);setTimeout(()=>setCopiedId(null),2000);
  };

  // Simple markdown renderer
  const renderContent=(text:string)=>{
    if(!text)return null;
    const lines=text.split("\n");
    const els:React.ReactNode[]=[];
    let i=0;
    while(i<lines.length){
      const line=lines[i];
      if(line.startsWith("```")){
        const codeLines:string[]=[];
        i++;
        while(i<lines.length&&!lines[i].startsWith("```")){codeLines.push(lines[i]);i++;}
        els.push(<pre key={i} style={{background:dark?"#121212":"#F1F5F9",border:`1px solid ${dark?"rgba(255,255,255,0.08)":"rgba(0,0,0,0.08)"}`,borderRadius:8,padding:"12px 14px",fontSize:12,overflowX:"auto" as const,fontFamily:"'SF Mono','Fira Code',monospace",lineHeight:1.6,margin:"8px 0",color:C.t1}}><code>{codeLines.join("\n")}</code></pre>);
        i++;continue;
      }
      if(line.startsWith("### ")){els.push(<div key={i} style={{fontSize:14,fontWeight:700,color:C.t1,marginTop:14,marginBottom:4}}>{inlineRender(line.slice(4))}</div>);i++;continue;}
      if(line.startsWith("## ")){els.push(<div key={i} style={{fontSize:15,fontWeight:800,color:C.t1,marginTop:16,marginBottom:6,letterSpacing:"-0.01em"}}>{inlineRender(line.slice(3))}</div>);i++;continue;}
      if(line.startsWith("# ")){els.push(<div key={i} style={{fontSize:17,fontWeight:800,color:C.t1,marginTop:18,marginBottom:8,letterSpacing:"-0.015em"}}>{inlineRender(line.slice(2))}</div>);i++;continue;}
      if(line.startsWith("- ")||line.startsWith("* ")){
        const items:string[]=[line.slice(2)];
        i++;
        while(i<lines.length&&(lines[i].startsWith("- ")||lines[i].startsWith("* "))){items.push(lines[i].slice(2));i++;}
        els.push(<ul key={i} style={{margin:"6px 0",paddingLeft:18,display:"flex",flexDirection:"column" as const,gap:3}}>{items.map((it,j)=><li key={j} style={{fontSize:14,color:C.t1,lineHeight:1.6}}>{inlineRender(it)}</li>)}</ul>);
        continue;
      }
      if(/^\d+\. /.test(line)){
        const items:string[]=[line.replace(/^\d+\. /,"")];
        i++;
        while(i<lines.length&&/^\d+\. /.test(lines[i])){items.push(lines[i].replace(/^\d+\. /,""));i++;}
        els.push(<ol key={i} style={{margin:"6px 0",paddingLeft:18,display:"flex",flexDirection:"column" as const,gap:3}}>{items.map((it,j)=><li key={j} style={{fontSize:14,color:C.t1,lineHeight:1.6}}>{inlineRender(it)}</li>)}</ol>);
        continue;
      }
      if(line==="---"||line==="***"){els.push(<hr key={i} style={{border:"none",borderTop:`1px solid ${dark?"rgba(255,255,255,0.08)":"rgba(0,0,0,0.08)"}`,margin:"12px 0"}}/>);i++;continue;}
      if(line.trim()===""){els.push(<div key={i} style={{height:8}}/>);i++;continue;}
      els.push(<div key={i} style={{fontSize:14,color:C.t1,lineHeight:1.7,marginBottom:2}}>{inlineRender(line)}</div>);
      i++;
    }
    return els;
  };

  const inlineRender=(text:string):React.ReactNode=>{
    const parts=text.split(/(\*\*[^*]+\*\*|`[^`]+`|\*[^*]+\*)/g);
    return parts.map((p,i)=>{
      if(p.startsWith("**")&&p.endsWith("**"))return<strong key={i} style={{fontWeight:700,color:C.t1}}>{p.slice(2,-2)}</strong>;
      if(p.startsWith("`")&&p.endsWith("`"))return<code key={i} style={{fontFamily:"monospace",fontSize:12,background:dark?"rgba(255,255,255,0.08)":"rgba(0,0,0,0.07)",padding:"1px 5px",borderRadius:4,color:C.t1}}>{p.slice(1,-1)}</code>;
      if(p.startsWith("*")&&p.endsWith("*"))return<em key={i}>{p.slice(1,-1)}</em>;
      return p;
    });
  };

  const bd=dark?"rgba(255,255,255,0.07)":"rgba(0,0,0,0.07)";
  const isEmpty=messages.length===0;
  const panelBg=dark?"#111111":"#fff";

  const rootH=isMobile?"calc(100vh - 134px)":"calc(100vh - 56px)";
  if(!mounted)return <div style={{height:rootH}}/>;

  return(
    <div style={{display:"flex",height:rootH,maxWidth:1180,margin:"0 auto",width:"100%",position:"relative" as const,overflow:"hidden"}}>

      {/* ===== LEFT: чат ===== */}
      <div style={{flex:1,minWidth:0,display:"flex",flexDirection:"column",height:"100%",borderRight:!isMobile&&showList?`1px solid ${bd}`:"none"}}>

        {/* Header */}
        <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",padding:"16px 24px 12px",borderBottom:`1px solid ${bd}`,flexShrink:0}}>
          <div style={{display:"flex",alignItems:"center",gap:12,minWidth:0}}>
            <img src={KS_AI_LOGO} width={36} height={36} style={{borderRadius:8,objectFit:"cover" as const,flexShrink:0}} alt="Kirill Scales AI"/>
            <div style={{minWidth:0}}>
              <div style={{fontSize:15,fontWeight:700,color:C.t1,letterSpacing:"-0.01em"}}>Kirill Scales AI</div>
              <div style={{fontSize:11,color:C.t2,fontWeight:500,display:"flex",alignItems:"center",gap:5}}>
                <div style={{width:6,height:6,borderRadius:"50%",background:loading?"#A7A7A7":"#808080"}}/>
                {loading?"Печатает…":"Твой персональный стратег по бизнесу"}
              </div>
            </div>
          </div>
          <div style={{display:"flex",gap:8,alignItems:"center",flexShrink:0}}>
            {messages.length>0&&<button onClick={clear} style={{padding:"6px 12px",borderRadius:8,border:`1px solid ${bd}`,background:"transparent",color:C.t2,fontSize:12,fontWeight:500,cursor:"pointer"}}>
              Очистить
            </button>}
            <button onClick={()=>setShowList(s=>!s)} title="Список чатов"
              style={{width:32,height:32,borderRadius:8,border:`1px solid ${showList&&!isMobile?"transparent":bd}`,background:showList&&!isMobile?(dark?"rgba(255,255,255,0.06)":"#F1F5F9"):"transparent",color:C.t2,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0}}>
              <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><line x1="8" y1="6" x2="21" y2="6"/><line x1="8" y1="12" x2="21" y2="12"/><line x1="8" y1="18" x2="21" y2="18"/><line x1="3" y1="6" x2="3.01" y2="6"/><line x1="3" y1="12" x2="3.01" y2="12"/><line x1="3" y1="18" x2="3.01" y2="18"/></svg>
            </button>
          </div>
        </div>

        {/* Messages */}
        <div style={{flex:1,overflowY:"auto" as const,padding:"20px 24px",display:"flex",flexDirection:"column",gap:16}}>
          {isEmpty&&(
            <div style={{display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",height:"100%",gap:20,paddingBottom:40}}>
              <img src={KS_AI_LOGO} width={64} height={64} style={{borderRadius:12,objectFit:"cover" as const}} alt="Kirill Scales AI"/>
              <div style={{textAlign:"center" as const}}>
                <div style={{fontSize:20,fontWeight:800,color:C.t1,marginBottom:6,letterSpacing:"-0.02em"}}>Kirill Scales AI</div>
                <div style={{fontSize:14,color:C.t2,maxWidth:360,lineHeight:1.6}}>Твой стратег и операционный центр платформы</div>
              </div>
              <div style={{display:"flex",flexWrap:"wrap" as const,gap:8,justifyContent:"center",maxWidth:500}}>
                {["Составь расписание на завтра","Что у меня по делам?","Добавь лида: Иван, Telegram, 50к","Покажи задачи на неделю"].map(s=>(
                  <button key={s} onClick={()=>{setInput(s);inputRef.current?.focus();}}
                    style={{padding:"8px 14px",borderRadius:10,border:`1px solid ${bd}`,background:dark?"rgba(255,255,255,0.04)":"#fff",color:C.t2,fontSize:13,cursor:"pointer",transition:"all 0.15s",fontFamily:"'Inter',sans-serif"}}
                    onMouseEnter={e=>{(e.currentTarget as HTMLElement).style.color=C.t1;(e.currentTarget as HTMLElement).style.borderColor=dark?"rgba(255,255,255,0.15)":"rgba(0,0,0,0.15)";}}
                    onMouseLeave={e=>{(e.currentTarget as HTMLElement).style.color=C.t2;(e.currentTarget as HTMLElement).style.borderColor=bd;}}>
                    {s}
                  </button>
                ))}
              </div>
            </div>
          )}

          {messages.map(msg=>(
            <div key={msg.id} style={{display:"flex",flexDirection:"column",alignItems:msg.role==="user"?"flex-end":"flex-start",gap:4}}
              onMouseEnter={()=>setHoveredId(msg.id)}
              onMouseLeave={()=>setHoveredId(null)}>
              {msg.role==="assistant"&&(
                <div style={{display:"flex",alignItems:"center",gap:6,marginBottom:2}}>
                  <img src={KS_AI_LOGO} width={20} height={20} style={{borderRadius:6,objectFit:"cover" as const,flexShrink:0}} alt=""/>
                  <span style={{fontSize:11,fontWeight:600,color:C.t2}}>Kirill Scales AI</span>
                </div>
              )}
              <div style={{
                maxWidth:"82%",
                padding:msg.role==="user"?"12px 16px":"14px 18px",
                borderRadius:msg.role==="user"?"16px 16px 4px 16px":"4px 16px 16px 16px",
                background:msg.role==="user"
                  ?"linear-gradient(135deg,#4F4F4F,#606060)"
                  :(dark?"rgba(255,255,255,0.05)":"#F8FAFC"),
                border:msg.role==="assistant"?`1px solid ${bd}`:"none",
                color:msg.role==="user"?"#fff":C.t1,
                fontSize:14,lineHeight:1.7,
                position:"relative" as const,
              }}>
                {msg.role==="user"
                  ?<div style={{fontSize:14,lineHeight:1.6}}>{msg.content}</div>
                  :msg.content
                    ?renderContent(msg.content)
                    :<div style={{display:"flex",gap:4,alignItems:"center",padding:"4px 0"}}>
                      {[0,1,2].map(i=><div key={i} style={{width:6,height:6,borderRadius:"50%",background:C.t2,animation:`bounce 1.2s ease-in-out ${i*0.15}s infinite`}}/>)}
                      <style>{`@keyframes bounce{0%,80%,100%{transform:translateY(0)}40%{transform:translateY(-5px)}}`}</style>
                    </div>
                }
              </div>
              {msg.role==="assistant"&&msg.content&&hoveredId===msg.id&&(
                <button onClick={()=>copyMsg(msg.content,msg.id)}
                  style={{padding:"4px 10px",borderRadius:7,border:`1px solid ${bd}`,background:dark?"rgba(255,255,255,0.04)":"#fff",color:C.t2,fontSize:11,cursor:"pointer",display:"flex",alignItems:"center",gap:5,fontFamily:"'Inter',sans-serif"}}>
                  {copiedId===msg.id
                    ?<><svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="#808080" strokeWidth="2.5"><polyline points="20 6 9 17 4 12"/></svg>Скопировано</>
                    :<><svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><rect x="9" y="9" width="13" height="13" rx="2"/><path d="M5 15H4a2 2 0 01-2-2V4a2 2 0 012-2h9a2 2 0 012 2v1"/></svg>Копировать</>
                  }
                </button>
              )}
            </div>
          ))}
          <div ref={endRef}/>
        </div>

        {/* Input */}
        <div style={{padding:"12px 24px 20px",borderTop:`1px solid ${bd}`,flexShrink:0,background:dark?"#0D0D0D":"#fff"}}>
          <div style={{display:"flex",gap:10,alignItems:"flex-end",background:dark?"rgba(255,255,255,0.04)":"#F8FAFC",border:`1px solid ${dark?"rgba(255,255,255,0.1)":"rgba(0,0,0,0.1)"}`,borderRadius:10,padding:"10px 12px 10px 16px",transition:"border-color 0.15s"}}>
            <textarea ref={inputRef}
              value={input}
              onChange={e=>{setInput(e.target.value);e.target.style.height="auto";e.target.style.height=Math.min(e.target.scrollHeight,160)+"px";}}
              onKeyDown={e=>{if(e.key==="Enter"&&!e.shiftKey){e.preventDefault();send();}}}
              placeholder="Напиши запрос... (Enter — отправить, Shift+Enter — новая строка)"
              rows={1}
              style={{flex:1,background:"transparent",border:"none",outline:"none",resize:"none" as const,fontSize:14,color:C.t1,lineHeight:1.6,fontFamily:"'Inter',sans-serif",maxHeight:160,overflowY:"auto" as const,padding:0}}
            />
            <button onClick={loading?stop:send}
              style={{width:36,height:36,borderRadius:9,border:"none",background:input.trim()||loading?"#4F4F4F":"rgba(0,0,0,0.08)",color:input.trim()||loading?"#fff":C.t2,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0,transition:"all 0.15s"}}>
              {loading
                ?<svg width="14" height="14" viewBox="0 0 24 24" fill="currentColor"><rect x="6" y="6" width="12" height="12" rx="2"/></svg>
                :<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><line x1="22" y1="2" x2="11" y2="13"/><polygon points="22 2 15 22 11 13 2 9 22 2"/></svg>
              }
            </button>
          </div>
          <div style={{fontSize:11,color:C.t2,textAlign:"center" as const,marginTop:8,opacity:0.5}}>Kirill Scales AI · Диалоги сохраняются автоматически</div>
        </div>
      </div>

      {/* ===== RIGHT: список чатов ===== */}
      {isMobile&&showList&&<div onClick={()=>setShowList(false)} style={{position:"absolute" as const,inset:0,background:"rgba(0,0,0,0.45)",zIndex:20}}/>}
      {showList&&(
        <div style={{
          width:isMobile?"82%":288,
          maxWidth:isMobile?340:288,
          flexShrink:0,
          height:"100%",
          display:"flex",flexDirection:"column",
          background:panelBg,
          ...(isMobile?{position:"absolute" as const,right:0,top:0,zIndex:30,borderLeft:`1px solid ${bd}`,boxShadow:"-8px 0 32px rgba(0,0,0,0.28)"}:{}),
        }}>
          {/* List header */}
          <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",padding:"16px 16px 12px",borderBottom:`1px solid ${bd}`,flexShrink:0}}>
            <div style={{fontSize:14,fontWeight:700,color:C.t1,letterSpacing:"-0.01em"}}>Список чатов</div>
            <button onClick={newChat}
              style={{display:"flex",alignItems:"center",gap:5,padding:"6px 11px",borderRadius:8,border:"none",background:"#4F4F4F",color:"#fff",fontSize:12,fontWeight:600,cursor:"pointer",fontFamily:"'Inter',sans-serif"}}>
              <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round"><line x1="12" y1="5" x2="12" y2="19"/><line x1="5" y1="12" x2="19" y2="12"/></svg>
              Новый
            </button>
          </div>

          {/* List body */}
          <div style={{flex:1,overflowY:"auto" as const,padding:8,display:"flex",flexDirection:"column",gap:4}}>
            {chats.map(c=>{
              const isAct=c.id===activeId;
              const gen=kirillAIStore.isGenerating(c.id);
              const last=c.messages[c.messages.length-1];
              const preview=last?(last.content?last.content.replace(/[#*`>\-]/g," ").replace(/\s+/g," ").trim():(gen?"Печатает…":"…")):"Пустой чат";
              const showDel=isMobile||hoverChat===c.id||isAct;
              return(
                <div key={c.id} onClick={()=>pickChat(c.id)}
                  onMouseEnter={()=>setHoverChat(c.id)} onMouseLeave={()=>setHoverChat(null)}
                  style={{
                    display:"flex",alignItems:"center",gap:8,
                    padding:"9px 10px",borderRadius:8,cursor:"pointer",
                    background:isAct?(dark?"rgba(135,135,135,0.14)":"rgba(96,96,96,0.08)"):"transparent",
                    border:`1px solid ${isAct?(dark?"rgba(135,135,135,0.28)":"rgba(96,96,96,0.18)"):"transparent"}`,
                    transition:"background 0.15s",
                  }}>
                  <div style={{flex:1,minWidth:0}}>
                    <div style={{display:"flex",alignItems:"center",gap:6}}>
                      {gen&&<div style={{width:6,height:6,borderRadius:"50%",background:"#A7A7A7",flexShrink:0,animation:"bounce 1.2s ease-in-out infinite"}}/>}
                      <div style={{fontSize:13,fontWeight:isAct?600:500,color:isAct?C.t1:C.t1,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{c.title||"Новый чат"}</div>
                    </div>
                    <div style={{fontSize:11,color:C.t2,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap",marginTop:2}}>{preview.slice(0,60)}</div>
                  </div>
                  {showDel&&<button onClick={e=>removeChat(c.id,e)} title="Удалить чат"
                    style={{width:24,height:24,borderRadius:6,border:"none",background:"transparent",color:C.t2,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0}}
                    onMouseEnter={e=>{(e.currentTarget as HTMLElement).style.color="#777777";(e.currentTarget as HTMLElement).style.background=dark?"rgba(119,119,119,0.12)":"rgba(119,119,119,0.08)";}}
                    onMouseLeave={e=>{(e.currentTarget as HTMLElement).style.color=C.t2;(e.currentTarget as HTMLElement).style.background="transparent";}}>
                    <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><polyline points="3 6 5 6 21 6"/><path d="M19 6v14a2 2 0 01-2 2H7a2 2 0 01-2-2V6m3 0V4a2 2 0 012-2h4a2 2 0 012 2v2"/></svg>
                  </button>}
                </div>
              );
            })}
          </div>
        </div>
      )}
    </div>
  );
}
